  ('locality-0a2fc18c-moex-00201', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '甲國生產小麥與稻米的生產可能線如圖所示，在自給自足未開放國際貿易的情況下，於A點進行 生產；在開放國際貿易後，生產點落在B點。甲國同時消費小麥與稻米。請問下列敘述何者錯誤？ 小麥 A B 稻米', '["甲國開放國際貿易前之消費點為A點", "甲國開放國際貿易後的消費點，落於生產可能線之外", "甲國開放貿易前，其國內稻米相對價格較國際相對價格為高", "與貿易對手國相較，甲國生產稻米具有比較利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00202', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '根據IS-LM模型，來自商品市場的投資支出增加時，為釘住利率不變，中央銀行可以採取下列何 種政策？', '["減少貨幣供給", "增加貨幣供給", "增加政府支出", "減少政府稅收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00203', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '如果需求是具有彈性的，那麼下列何者正確？', '["價格效果大於數量效果，價格的下降將導致總收入增加", "價格效果大於數量效果，價格的增加將導致總收入增加", "數量效果大於價格效果，價格的增加將導致總收入增加", "數量效果大於價格效果，價格的下降將導致總收入增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00204', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '在其他條件不變情況下，廠商增加僱用員工使得它的邊際產量上升，則該廠商的：', '["短期平均總成本小於邊際成本", "短期平均變動成本大於邊際成本", "短期平均總成本上升", "邊際成本上升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00205', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '假設廠商的成本函數為C(q)=20+3q，其中C為總成本，而q則為總產量。下列敘述何者正確？', '["邊際成本函數為3q", "平均成本函數為3q", "固定成本函數為3q", "此成本函數為一短期成本函數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00206', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '某產品的市場需求函數為Q(P)=290-P，如果市場中有三家廠商生產該產品，且固定生產成本均 為200，邊際生產成本亦均為固定值10，當廠商從事數量競爭時，奈許均衡（Nashequilibrium） 下個別廠商的利潤為：', '["4,700", "4,900", "5,200", "5,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00207', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '假設目前完全競爭市場處於短期均衡，下列有關個別廠商的短期利潤和生產者剩餘敘述，何者正確？', '["至少有一家廠商的利潤是正值", "至少有一家廠商的利潤是負值", "每一家廠商的生產者剩餘都一定是大於或等於零", "每一家廠商的利潤都一定是大於或等於零"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00208', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '在一個小國裡，政府原先只允許一家廠商生產電視機，如果現在政府決定開放其他廠商生產電視 機，則該市場的：', '["消費者剩餘下降", "生產者剩餘下降", "社會福利下降", "社會福利不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
  ('locality-0a2fc18c-moex-00209', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-110-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '當對某個活動課稅的稅額等於這個活動的外部邊際成本時，達到有效率的生產水準，是因為課稅：', '["達到競爭均衡", "強迫生產者承擔所有的外部成本", "保證廠商能有更高的利潤", "消除所有污染 31460、31860"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:18+00:00", "source_pdf_sha1": "93d510670c35", "answer_pdf_sha1": "35a08a6bdee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "318", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL)
